import * as React from 'react';
import { ToastContainer } from "react-toastify";
import ReactGA from 'react-ga';
import LandingPage from '../page/ad';
import 'react-toastify/dist/ReactToastify.css';

import {
  BrowserRouter as Router,
  Switch,
  Route,
} from "react-router-dom";


ReactGA.initialize('UA-161751094-1', { debug: false });

class App extends React.Component {
  constructor(props) {
    super(props)
  }
  public render(): JSX.Element {
    return (
      <>
      <Router basename="/">
      <div>
        <Switch>
          <Route exact path="/" render={(props) => <LandingPage {...props} categoryId='5e787274718ca8fb23efc5ea' />}></Route>
          <Route exact path="/ad" render={(props) => <LandingPage {...props} categoryId='5e787274718ca8fb23efc5ea' />}></Route>
          <Route exact path="/phim" render={(props) => <LandingPage {...props} categoryId='5e787274718ca8fb23efc5ea' />} ></Route>
          <Route exact path="/mienphi" render={(props) => <LandingPage {...props} categoryId='5e7ad69a718ca8fb23f33da3' />} ></Route>
        </Switch>
      </div>
    </Router>
    <ToastContainer autoClose={2000} className='toast-container-custom'/>
      </>
    );
  }
}

export default App;



