export const COMMON_TYPES = {
	UPDATE_COLLAPSED: 'UPDATE_COLLAPSED',
	SET_ERROR_MESSAGE: 'SET_ERROR_MESSAGE',
	GET_CONFIGS: 'GET_CONFIGS',
    SET_CONFIG: 'SET_CONFIG',
    GET_VIDEO_BY_ID: 'GET_VIDEO_BY_ID',
    SET_VIDEO_ON_LANDING_PAGE: 'SET_VIDEO_ON_LANDING_PAGE',
    AUTO_LOGIN: 'AUTO_LOGIN',
    FETCH_VIDEO_ON_LANDING_PAGE: 'FETCH_VIDEO_ON_LANDING_PAGE',
    GET_VIDEO_URL: 'GET_VIDEO_URL',
    SET_VIDEO_URL: 'SET_VIDEO_URL',
    SHOW_HIDE_LOADING: 'SHOW_HIDE_LOADING',
    SET_PACKAGE: 'SET_PACKAGE',
    CONFIG_SMS: 'CONFIG_SMS',
    ADD_ALL_PACKAGE: 'ADD_ALL_PACKAGE',
    FETCH_CURRENT_ITEM: 'FETCH_CURRENT_ITEM',
    UPDATE_INFO_ACCOUNT: 'UPDATE_INFO_ACCOUNT',
    SHOW_HIDE_LOADMORE: 'SHOW_HIDE_LOADMORE'
}

export function updateCollapsed(status: Boolean) {
	return { 
		type: COMMON_TYPES.UPDATE_COLLAPSED,
		payload: status
	}
}

export function getConfigs() {
    return {
        type: COMMON_TYPES.GET_CONFIGS
    }
}

export function setConfig (arr: any) {
    return {
        type: COMMON_TYPES.SET_CONFIG,
        payload: arr
    }
}

export function getVideoById(data: Object) {
    return {
        type: COMMON_TYPES.GET_VIDEO_BY_ID,
        payload: data
    }
}

export function setVideoOnLandingPage(data: any) {
    return {
        type: COMMON_TYPES.SET_VIDEO_ON_LANDING_PAGE,
        payload: data
    }
}

export function autoLogin(data: any) {
    return {
        type: COMMON_TYPES.AUTO_LOGIN,
        payload: data
    }
}


export function fetchVideoLandingPage() {
    return {
        type: COMMON_TYPES.FETCH_VIDEO_ON_LANDING_PAGE,
    }
}

export function getVideoUrl(data: Object) {
    return {
        type: COMMON_TYPES.GET_VIDEO_URL,
        payload: data
    }
}

export function setVideoUrl(url: string) {
    return {
        type: COMMON_TYPES.SET_VIDEO_URL,
        payload: url
    }
}

export function showHideLoading(status: boolean) {
    return {
        type: COMMON_TYPES.SHOW_HIDE_LOADING,
        payload: status
    }
}

export function setPackage(data: any) {
    return {
        type: COMMON_TYPES.SET_PACKAGE,
        payload: data
    }
}

export function setConfigSMS(data: any) {
    return {
        type: COMMON_TYPES.CONFIG_SMS,
        payload: data
    }
}

export function addAllPackage(data: any) {
    return {
        type: COMMON_TYPES.ADD_ALL_PACKAGE,
        payload: data
    }
}

export function fetchCurrentItem() {
    return {
        type: COMMON_TYPES.FETCH_CURRENT_ITEM,
    }
}

export function updateInfoAccount(s: any) {
    return {
        type: COMMON_TYPES.UPDATE_INFO_ACCOUNT,
        payload: s
    }
}
export function hideLoadmore(s: any) {
    return {
        type: COMMON_TYPES.SHOW_HIDE_LOADMORE,
        payload: s
    }
}



