import React from 'react'

class Modal extends React.Component<any, any> {
	render(): JSX.Element {
		return (
            <div className={`modal-container ${this.props.show ? 'show' : ''}`} id="modal-container">
            <div className="modal-content">
                <h3 className="m-title">{this.props.title}</h3>
                <p className="m-content" dangerouslySetInnerHTML={{__html: this.props.content}}></p>
                <div className="m-action" id="m-action">
                    <div className={`modal-btn-ok`} onClick={this.props.onOk} id="modal-btn-ok">Đồng ý</div>
                    <div className={`modal-btn-close`} id="modal-btn-close" onClick={this.props.onCancle}>Huỷ</div>
                </div>
            </div>
            </div>
		)
	}
}

export default Modal;


