import { all, fork, takeLatest, select, put } from 'redux-saga/effects'
import { PURCHASE_TYPES } from '../stores/purchase/PurchaseAction';
import { configs, GA_CATEGORY, GA_EVENT, _http } from '../common';
import Base64 from 'crypto-js/enc-base64'
import ReactGA from 'react-ga';
import hmacSHA1 from 'crypto-js/hmac-sha1';
import _ from 'lodash';
import { toast } from 'react-toastify';
import { setVideoOnLandingPage, showHideLoading } from '../stores/common/CommonAction';
import { StatusCode } from 'src/assets/variables';
const getCommon= (state: any) => state.common;
function* create(action: any) {
	yield put (showHideLoading(true));
	try {
	let payload = action.payload;
	let token = localStorage.getItem(configs.token)
	// let token = parseCookies(ctx)[configs.token] ? parseCookies(ctx)[configs.token] : '';
	let token_secret = ''
	if(token) {
		token_secret = JSON.parse(token).token_secret;
	}
	const res = yield _http.get(`/api1/purchases/now`)
	let nonce = '';
	for(let i = 0; i < 6; i++) {
	  nonce +=	_.random(1, 9);
	}
	let _product = {
		product_id: payload.id,
		product_name: payload.name,
		product_type: payload.type,
		product_category: payload.category,
		rental_period: payload.rental_period ? payload.rental_period : 1,
		amount: payload.amount ? payload.amount : 3000,
		auto_renewal: payload.auto_renewal,
		ts: res.data.time,
		client_id: configs.clientId,
		nonce: nonce,
		hash: '',
		purchase_id: '',
		currency: 'VND',
      	normal: 0,
      	normal_vat: 0,
      	point: 0,
      	sale_code: configs.sale_code
	}
	let _hash = _product.client_id + _product.product_id + _product.ts + _product.nonce;
	_product.hash = encodeURIComponent(Base64.stringify(hmacSHA1(_hash, token_secret)));
	const _create = yield _http.post(`/api1/purchases/create?hash=${_product.hash}&product_id=${_product.product_id}&product_name=${_product.product_name}
	&product_type=${_product.product_type}&product_category=${_product.product_category}&auto_renewal=${_product.auto_renewal}
	&ts=${_product.ts}&client_id=${_product.client_id}&nonce=${_product.nonce}&rental_period=${_product.rental_period}`, _product)

	if(_create && _create.status === StatusCode.SUCCESS) 
		_product.purchase_id = _create.data.id;

	let paymentsRq = yield _http.post(`/api1/payments/create?sale_code=${_product.sale_code}&currency=${_product.currency}&product_id=${_product.product_id}&product_name=${_product.product_name}
	&product_category=${_product.product_category}&product_type=${_product.product_type}&phone=${_product.amount}&purchase_id=${_product.purchase_id}`)
	yield put (showHideLoading(false));
	if(paymentsRq) {
		const payments = paymentsRq.data
		if(payments && payments.id) {
			let stateCommon = yield select(getCommon);
			let __data = stateCommon.landingPageVideos;
			try {
				let __p = Base64.stringify(hmacSHA1(stateCommon.infoAccount.id, configs.vtpsecetkey))
				ReactGA.event({
					category: GA_CATEGORY.REGISTER,
					action: GA_EVENT.REGISTER_SUCCESS,
					label: `${__p} - ${_product.product_name}`
				});
			}catch(ex) {

			}
			if(__data && __data.length > 0) {
				_.forEach(__data, function(item) {
					item.program.isPurchased = true;
					item.program.acceptPlay = true;
				})
				yield put (setVideoOnLandingPage(__data))
			}
		} else if(payments.error && payments.error.code) {
			let _message = ''
			switch (payments.error.code) {
				case 'U0252':
					_message = 'Tài khoản không đủ để đăng ký dịch vụ, Quý khách vui lòng kiểm tra và thử lại. Trân trọng';
				break;
				case 'U0232':
					_message = 'Tài khoản trong ví điện tử của bạn không đủ.';
				break;
				case 'U0503':
				_message = 'Không thể kết nối với máy chủ BMS. Vui lòng thử lại.';
				break;
				default:
				_message = 'Có lỗi trong quá trình thanh toán';
				break;
			}
			toast.info(_message)
		}
	}
	}catch(Ex) {
		yield put (showHideLoading(false));
        console.log("function*create -> Ex", Ex)
		
	}
}


function* actionWatcher() {
	yield takeLatest(PURCHASE_TYPES.CREATE , create)
}

export default function* purchaseSaga() {
	yield all([fork(actionWatcher)]);
}


