import React from 'react'
import { connect } from 'react-redux'
import HlsPlayer from '../components/HlsPlayer'
import VideoLandingPage from '../components/VideoLandingPage'
import Modal from '../components/Modal'
import ReactGA from 'react-ga';
import { getVideoById, setVideoOnLandingPage, autoLogin, getVideoUrl } from '../stores/common/CommonAction'
import { ILandingPageFilterVideo } from '../assets/types'
import { configs, initDefault, GA_CATEGORY, GA_EVENT } from '../common'
import { create } from '../stores/purchase/PurchaseAction'
import { Period } from '../assets/variables'
import '../styles/landing.scss'



const mapDispatchToProps = (dispatch: any) => {
	return {
		getVideoById: (data: any)=> dispatch(getVideoById(data)),
		setVideoOnLandingPage: (data: Array<any>) => dispatch(setVideoOnLandingPage(data)),
		autoLogin: (data: Object) => dispatch(autoLogin(data)),
		getVideoUrl:(data: Object) => dispatch(getVideoUrl(data)),
		create: (data: any) => dispatch(create(data))
	}
}

const mapStateToProps = (state: any) => ({
	confirmSMS: state.common.confirmSMS,
	isLogin: state.auth.isLogin,
	landingPageVideos: state.common.landingPageVideos,
	allPackageById: state.common.allPackageById,
	isShowLoading: state.common.isShowLoading,
	videoUrl: state.common.videoUrl,
	listPackage: state.common.listPackage,
	fetchCurrentItem: state.common.fetchCurrentItem,
	hideLoadmore: state.common.hideLoadmore
  });
class LandingPage extends React.Component<any, any> {
	constructor(props: any) {
		super(props);
		this.state = {
			listVideo: [],
			skipIndex: 1,
			visible: false,
			currentItem: null,
			currentCategoryId: '',
			model: '',
			period: 1,
			confirmSMS: ''
		}
    }

	componentDidMount() {
		initDefault();
		const queryString = window.location.search;
		const urlParams = new URLSearchParams(queryString)
        console.log("LandingPage -> componentDidMount -> urlParams", urlParams)
		const device_browser = localStorage.getItem(configs.device_browser);
		configs.deviceObj = {
			...configs.deviceObj,
			id: device_browser ? device_browser : ''
	  }


	  const filterVideo: ILandingPageFilterVideo = {
			isInit: true,
			videoId: urlParams.get('videoId') ? urlParams.get('videoId') : '',
			categoryId: this.props.categoryId ? this.props.categoryId : urlParams.get('categoryId') ? urlParams.get('categoryId'): configs.defaultCategoryId,
			offset: 0,
			limit: 5
		}
		const params = {
			filterVideo: filterVideo,
			device: configs.deviceObj,
		}
		this.setState({
			currentCategoryId: filterVideo.categoryId,
			model: configs.model
		})
		this.props.autoLogin(params);
	}

	componentWillReceiveProps(nextProps) {
		if(this.props.fetchCurrentItem !== nextProps.fetchCurrentItem) {
			this.setState({
				currentItem: nextProps.landingPageVideos[0]
			})
		}
	}


	sortList(video: any, index: number) {
		let listVideo = this.props.landingPageVideos;
		listVideo.splice(index, 1);
		listVideo.unshift(video);
		this.props.setVideoOnLandingPage(listVideo)
	}

	selectVideo = (video: any, index: number) => {
		let slug = video.program.id;
        let urlParams = new URLSearchParams(window.location.search)
        urlParams.set('videoId', slug)
        this.props.history.replace(`/ad?${urlParams.toString()}`)
		let payload = {
			id: video.program.id,
			productId: video.program.singleProductId,
			locator: video.program.locator
		}
		this.props.getVideoUrl(payload);
		this.sortList(video, index)
	}

	skipVideo() {
		if(this.state.skipIndex + 1 <= 4) {
			let video = this.props.landingPageVideos[this.state.skipIndex];
			this.sortList(video, this.state.skipIndex);
			this.setState({
				skipIndex: this.state.skipIndex + 1
			})
		} else {
			this.openApp();
			this.setState({
				skipIndex: 1
			})
		}
	}

	getMore(){
		let more = {
			categoryId: this.state.currentCategoryId,
			isInit: false
		}
		this.props.getVideoById(more);
	}

	openApp() {
		switch(configs.model) {
			case 'iOS':
				window.open('https://apps.apple.com/vn/app/vietteltv/id1015360393?l=vi', '_blank');
				break;
			case 'Android':
				window.open('https://play.google.com/store/apps/details?id=com.alticast.viettelphone&hl=en', '_blank');
				break;
		}
	}

	downApp () {
		ReactGA.event({
			category: GA_CATEGORY.ACTION_CLICK,
			action: GA_EVENT.CLICK_BUTTON_DOWNLOAD
		});
		this.openApp();
	}

	buy() {
		ReactGA.event({
			category: GA_CATEGORY.ACTION_CLICK,
			action: GA_EVENT.CLICK_BUTTON_REGISTER,
		});
		if(this.props.isLogin) {
			if(this.props.confirmSMS && this.props.confirmSMS.status === '1') {
				let period = Period.D;
				try {
					const urlParams = new URLSearchParams(window.location.search)
					if(urlParams && urlParams.get('period')) {
						period = urlParams.get('period')
					}
				}catch(ex){
					
				}
				let _sms = this.props.confirmSMS.content[period] && this.props.confirmSMS.content[period].length > 10 ? this.props.confirmSMS.content[period] : this.props.confirmSMS.content
				this.setState({
					period: period,
					confirmSMS: _sms
				})
				this.showModal();
			}
		} else {
			this.openApp()
		}
		
	}
	showModal = () => {
	this.setState({
	  visible: true,
	});
  };


  handleOk = () => {
	this.setState({
	  visible: false,
		});
	
		let _package = this.props.listPackage[this.state.period];
		try {
			if(this.props.allPackageById[_package.id] && this.props.allPackageById[_package.id][this.state.period]) {
				_package.rental_period = this.props.allPackageById[_package.id][this.state.period].period
				_package.amount = this.props.allPackageById[_package.id][this.state.period].price
			}
		}catch(Ex) {

		}
		this.props.create(_package);
  };

  handleCancel = () => {
	this.setState({
	  visible: false,
	});
  };
	
    public render(): JSX.Element {
		return (
			<div className="landing-page">
					<div id="overlay"  style={{ display: this.props.isShowLoading ? 'block' : 'none' }}>
						<div id="loading" ></div>
					</div>
				<div className={`content ${this.props.landingPageVideos && this.props.landingPageVideos.length > 0 ? 'show': 'hide'}`}>
				<div className="header">
					<div className="icon">
						<span></span>
					</div>
					<span className="text">
						Tải App để xem hơn 150 Kênh truyền hình và hàng vạn Phim HD bom tấn. Miễn cước truy cập 3G/4G tốc độ cao.
					</span>

					<div className="icon-download" onClick={ () => this.downApp()}>
						<span className={`${this.state.model === 'iOS' ? 'ios' : 'android' }`}></span>
					</div>
				</div>
				<div className="player-content">
					<HlsPlayer url={this.props.videoUrl} isLogin={this.props.isLogin} isShowBtnLandingPage buy={this.buy.bind(this)} openApp={this.openApp.bind(this)}  skipVideo={this.skipVideo.bind(this)} item={this.state.currentItem && this.state.currentItem}></HlsPlayer>
				</div>
				<div className="list-item">
					<h3>Liên quan</h3>
					<VideoLandingPage videos={this.props.landingPageVideos} selectVideo={this.selectVideo}></VideoLandingPage>
				</div>
				<div className={`more ${this.props.hideLoadmore > 0 ? 'hide': 'show'}`} onClick={this.getMore.bind(this)} >
					<div className="icon-more">
						<span className="icon-down"></span>
						<span>Xem thêm</span>
					</div>
				</div>
				<Modal content={this.state.confirmSMS} title="Thông báo" onOk={this.handleOk} show={this.state.visible} onCancle={this.handleCancel}></Modal>
				</div>
			</div>
		)
	}
}

export default connect(mapStateToProps, mapDispatchToProps)(LandingPage)


