import { AUTH_TYPES } from './AuthAction'
import IAction from '../IAction';
export default class AuthReducer {

    private static readonly _initialState = {
        isLogin: false,
    };

    public static reducer(state = AuthReducer._initialState, action: IAction<any>) {
        switch (action.type) {
            case AUTH_TYPES.SET_STATUS_LOGIN:
                return {
                    ...state,
                    isLogin: action.payload
                }
            default:
                return state;
        }
    }

}


