import { all, fork, put, call, select, takeEvery } from 'redux-saga/effects'
import { COMMON_TYPES, setConfig, setVideoOnLandingPage, setVideoUrl, showHideLoading, setPackage, setConfigSMS, addAllPackage, updateInfoAccount, hideLoadmore } from '../stores/common/CommonAction'
// import { setFilterChannelString, setChannelMap } from '../store/home/action'
import { configs, _http } from '../common'
import { IGroupChannel } from '../assets/types'
import { TypeProduct, ClassProduct, StatusCode } from '../assets/variables'
import Base64 from 'crypto-js/enc-base64'
import hmacSHA1 from 'crypto-js/hmac-sha1';
import _ from 'lodash'
import { setStatusLogin } from '../stores/auth/AuthAction'
const getCommon= (state: any) => state.common;
const getAuth= (state: any) => state.auth;

let paramsGetVideo = {
	offset: 0,
	limit: 0
}


function checkFree(product: any) {
	let listLocation = [];
	let data = {
		isFree: false,
		locator: '',
		encryption: false
	}
	// if(product.hidden === 'true') return data;

	if(product.location){
		listLocation.push(product.location)
	}
	if(product.locations) {
		listLocation = listLocation.concat(product.locations);
	}


	_.forEach(listLocation, function(item) {
		if(item.device === ClassProduct.HANDHELD.toLowerCase() || item.device === ClassProduct.TV_SMART.toLowerCase()) {
			if(data.locator.length === 0)
				data.locator = item.locator;
			if(item.encryption === 'true') {
				data.encryption = true;
			}
		}
		_.forEach(item.parameter, function(param) {
			if(param.name === 'Audience' && param.value === 'private:All' && product.hidden === 'false') {
				data.isFree = true;
			}
		})
	})

	if(product.price && !data.isFree && product.hidden === 'false') {
		if(product.price.length === 0) {
			data.isFree = true;
			return data;
		}
		_.forEach(product.price, function(item) {
			if(item.currency === 'VND' && item.value === 0) {
				data.isFree = true;
				return data;
			}
		}) 
    }
	return data;
}
let _isExpiredDate = false;
function checkPurchased(product: any) {
	_isExpiredDate = false;
	if(product.purchase && product.purchase.expired_date) {
		let parts = product.purchase.expired_date.match(/\d+/g);
		let expiredDate = new Date(parts[0], parts[1] - 1, parts[2], parts[3], parts[4], parts[5]);

		if(expiredDate.getTime() > new Date().getTime()) {
			_isExpiredDate = true;
		}
	}
	if(product && product.purchase && (product.purchase.expired_date && _isExpiredDate || !product.purchase.expired_date)) {
		return true;
	}
	return false;
}

export function convertToVOD(data: Array<any>) {
	let _data = []
	_.forEach(data, function(value) {
		let program = value.program;
		let products = value.product;
		program.itemImage = `${configs.baseHttpURL}/api1/contents/pictures/${program.id}?width=360.000000&height=516.000000`;
		program.bigImage = `${configs.baseHttpURL}/api1/contents/pictures/${program.id}`;
		if(program.likes && program.likes.data && program.likes.data.length > 0) {
			program.isLiked = true;
		}
		program.isFree = false;
		program.isPurchased = false;
		program.acceptPlay = false;
		program.name = program.title && program.title[0] && program.title[0].text ? program.title[0].text : '';
		program.description = program.synopsis && program.synopsis[0] && program.synopsis[0].text ? _.truncate(program.synopsis[0].text, { 'length': 300, 'separator': '' }) : '';
		_.forEach(products, function(product) {
			if(_.indexOf(product.cclass, ClassProduct.HANDHELD) !== -1 || _.indexOf(product.cclass, ClassProduct.TV_SMART) !== -1) {
				if(product.type === TypeProduct.SINGLE) {
					program.singleProductId = product.id
				}
				let _productCheckFree = checkFree(product);
				if(!program.isFree) program.isFree = _productCheckFree.isFree;
				if(!program.isPurchased) program.isPurchased = checkPurchased(product);
				if(program.isFree || program.isPurchased) {
					program.acceptPlay = true;
				}
				program.locator = _productCheckFree.locator;
				program.isEncrypted = _productCheckFree.encryption;
			}
		})
		_data.push({isFree: program.isFree,isPurchased: program.isPurchased })
	
	})
	return data;
}

export function* getConfigs(payload: any) {
	// let ctx = payload ? payload.ctx : {}
//   const response = yield _fetch(`${configs.baseURL}/api1/contents/platform`, null, null, ctx)
	const rq = yield _http.get('/api1/contents/platform')
	let config = {
		filterChannelString: '',
		filterChannelArray: [],
		mapChannel: {},
		groupChannel: Array<IGroupChannel>()
	}
	if(rq && rq.status === 200) {
		const response = rq.data
		yield put (setConfig(response.platform.config));
		for(let i = 0; i < response.platform.config.length; i++) {
			let item = response.platform.config[i];
			switch (item.name) {
				case configs.typeChannel:
					let value = JSON.parse(item.value);
					for(let j = 0; j < value.length; j++) {
						let _item = value[j];
						switch(_item.genre) {
							case 'all':
								let allChannelStr = _item.listData.toString();
								config.filterChannelArray = _item.listData;
								config.filterChannelString = allChannelStr;
								break;
							default:
								let grounp: IGroupChannel = {
									..._item,
									listChannel: Array<any>()
								}
								config.groupChannel.push(grounp);
								break;
							}
						}
						break;
					case configs.mapChannel: 
						let channel = JSON.parse(item.value);
						let newChannel = _.invert(channel);
						config.mapChannel = newChannel;
						break;
					case configs.listPackage: 
					 let _package = JSON.parse(item.value);
					 yield put (setPackage(_package))
					break;
					case configs.confirmSMS:
						let sms = JSON.parse(item.value);
						yield put (setConfigSMS(sms));
						break;
			}

		}
	}
	return config;
}

export function* getVideoById(action: any) {
	let mutiRequest = [];
	let payload = action.payload;
	yield put(hideLoadmore(false))
	if(!payload.isInit) {
		yield put (showHideLoading(true));
	}

	if(payload && payload.categoryId) {
		if(!payload.isInit) {
			payload.offset = paramsGetVideo.limit,
			payload.limit = paramsGetVideo.limit + configs.moreItem
		}
		mutiRequest.push(
			call(function() {
				return _http.get(`/api1/contents/categories/${payload.categoryId}/programs?include=product,fpackage,multilang,purchase,purchased&child=all&format=long&until=now&offset=${payload.offset}&limit=${payload.limit}`)
			})
		)
	}
	if(payload && payload.videoId) {
		mutiRequest.push(
			call(function() {
				return _http.get(`/api1/contents/programs/${payload.videoId}?include=product,fpackage,multilang,purchase,purchased&format=long&child=all`)
			})
		)
	}
	const res = yield all (mutiRequest);
    console.log("function*getVideoById -> res", res)
	if(payload.isInit) {
		let response  = {
			listCategory: res[0] && res[0].status === 200 ? res[0].data : null,
			video: res[1] && res[1].status === 200 ? res[1].data : null
		}

		let listVideoByCategory = response.listCategory ? response.listCategory.data : null;
		let video = response.video ? response.video : null
		if(video && listVideoByCategory) {
			_.remove(listVideoByCategory, function(item: any) {
				return item.program.id === video.program.id;
			  });
			listVideoByCategory.unshift(video);
			listVideoByCategory = convertToVOD(listVideoByCategory);
			yield put (setVideoOnLandingPage(listVideoByCategory))
		} else {
			if(listVideoByCategory) {
				listVideoByCategory = convertToVOD(listVideoByCategory);
				yield put (setVideoOnLandingPage(listVideoByCategory))
			}
		}
		if(listVideoByCategory) {
			paramsGetVideo.limit = payload.limit,
			paramsGetVideo.offset = payload.offset
			let infoVideo = {
				payload: {
					id: listVideoByCategory[0].program.id,
					productId: listVideoByCategory[0].program.singleProductId,
					locator: listVideoByCategory[0].program.locator,
				}
			}
			let auth = yield select(getAuth)
			if(auth.isLogin)
				yield getVideoUrl(infoVideo);
		}
	} else {
		let listVideoByCategory = res[0] && res[0].status === 200 ? res[0].data.data : null;
		console.log("function*getVideoById -> listVideoByCategory.length", listVideoByCategory.length, configs.moreItem)

		if(listVideoByCategory.length < configs.moreItem) {
			yield put(hideLoadmore(true))
		}
		if(listVideoByCategory) {
			paramsGetVideo = {
				offset: payload.offset,
				limit: payload.limit
			}
			let stateCommon = yield select(getCommon);
			listVideoByCategory = convertToVOD(listVideoByCategory);
			listVideoByCategory = stateCommon.landingPageVideos.concat(listVideoByCategory)
			yield put (setVideoOnLandingPage(listVideoByCategory))
		}
	}
	yield put (showHideLoading(false));
	// return res
}


export function* autoLogin(action: any) {

	yield put (showHideLoading(true))
	let _device = action.payload.device;
	let _hash = Base64.stringify(hmacSHA1(`${_device.id}${configs.clientId}`, configs.app_secret))
	let params = {
		hash: _hash,
		client_id: configs.clientId,
		device: _device,
		inspection: true
	}

	const rq = yield call(function() {
		return _http.post(`/ott/accounts/automatic_detection`, params)
	})
	
	if(rq && rq.status === StatusCode.SUCCESS) {
		let _response = rq.data;
		configs.tokenObj = _response;
		let responseStr = JSON.stringify(_response);
		localStorage.setItem(configs.token, responseStr);
		const infoAcc = yield call(function() {
			return _http.get('ott/accounts/show?include=device')
		})
		if(infoAcc && infoAcc.status === StatusCode.SUCCESS) {
			yield put(updateInfoAccount(infoAcc.data))
		}
		yield put (setStatusLogin(true))
		yield getVideoById({
			payload: {
				...action.payload.filterVideo,
			}
		})
		yield call(getAllPackage)
	} else {
		localStorage.removeItem(configs.token);
		yield getVideoById({
			payload: {
				...action.payload.filterVideo,
			}
		})
		yield put (setStatusLogin(false))
	}
	yield call(getConfigs, {});
}

function* getAllPackage() {
	let _url = `/api1/contents/fullpackages?format=long&include=product&include=multilang&include=purchase&include=fpackage`;
	const _rq = yield call(function() {
		return _http.get(_url)
	})
	
	if(_rq && _rq.status === 200) {
		const _response = _rq.data
		let _data = _response.data;
		_.forEach(_data, (item) => {
			if(item.rental_periods) {
				_.forEach(item.rental_periods, function(_p) {
					switch(_p.period) {
						case 1:
							item[1] = {
								price: _p.price ? _p.price[0].value : 0,
								period: _p.period
							}
							break;
						case 7:
							item[7] = {
								price: _p.price ? _p.price[0].value : 0,
								period: _p.period
							}
							break;
						case 30:
							item[30] = {
								price: _p.price ? _p.price[0].value : 0,
								period: _p.period
							}
							break;
					}
				})
			}
		})
		yield put(addAllPackage({
			allPackage : _data,
			allPackageById: _.keyBy(_data, 'id')
		}))
	}
}
export function* getVideoUrl(action: any) {
	let payload = action.payload;
	let access_token = configs.access_token
	if(typeof(localStorage) !== 'undefined') {
		let token: any = localStorage.getItem(configs.token);
		if(token) {
			token = JSON.parse(token);
			access_token = token.access_token
		}
	}

	let url = `/api1/watches/vod/prepare?id=${payload.id}&product_id=${payload.productId}&region_id=GUEST&version=1&bw_profile=5&category_id=VC_OTT&service_provider=SmartTV`
	if(access_token) {
		url += `user_id=${access_token}`
	}
	const _rq = yield call(function() {
		return _http.get(url)
	})
	if(_rq && _rq.status === 200) {
		
		let json = _rq.data;
		let requestId= json.gsdm && json.gsdm.vod_request_id ? json.gsdm.vod_request_id : '';
		let glbAddresses = json.gsdm && json.gsdm.glb_addresses ? json.gsdm.glb_addresses[json.gsdm.glb_addresses.length - 1] : '';
		let stream = `http://${glbAddresses}/${payload.locator}?AdaptiveType=HLS&VOD_RequestID=${encodeURIComponent(requestId)}`;
		yield put (setVideoUrl(stream))
		return stream
	}
}
function* commonWatcher() {
	yield takeEvery(COMMON_TYPES.GET_CONFIGS , getConfigs)
	yield takeEvery(COMMON_TYPES.GET_VIDEO_BY_ID, getVideoById)
	yield takeEvery(COMMON_TYPES.AUTO_LOGIN, autoLogin)
	yield takeEvery(COMMON_TYPES.GET_VIDEO_URL, getVideoUrl)
}

export default function* commonSaga() {
	yield all([fork(commonWatcher)]);
}


