import { COMMON_TYPES } from './CommonAction'
import IAction from '../IAction';
export default class CommonReducer {

    private static readonly _initialState = {
        collapsed: true,
        access_token: '',
        configs: {},
        landingPageVideos: [],
        videoUrl: '',
        isShowLoading: false,
        listPackage: {},
        confirmSMS: {},
        allPackage: [],
        allPackageById: [],
        fetchCurrentItem: false,
        infoAccount: {},
        hideLoadmore: false
    };

    public static reducer(state = CommonReducer._initialState, action: IAction<any>) {
        switch (action.type) {
            case COMMON_TYPES.UPDATE_COLLAPSED:
              return {
                ...state,
                collapsed: action.payload 
              }
            case COMMON_TYPES.SET_CONFIG: {
              return {
                  ...state,
                  configs: action.payload
              }
            }
            case COMMON_TYPES.SET_VIDEO_ON_LANDING_PAGE: {
              return {
                ...state,
                landingPageVideos: action.payload,
                fetchCurrentItem: !state.fetchCurrentItem
              }
            }
            case COMMON_TYPES.SET_VIDEO_URL: { 
              return {
                ...state,
                videoUrl: action.payload
              }
            }
            case COMMON_TYPES.SHOW_HIDE_LOADING: {
              return {
                ...state,
                isShowLoading: action.payload
              }
            }
            case COMMON_TYPES.SET_PACKAGE: {
              return {
                ...state,
                listPackage: action.payload
              }
            }
            case COMMON_TYPES.CONFIG_SMS: {
              return {
                ...state,
                confirmSMS: action.payload
              }
            }
            case COMMON_TYPES.ADD_ALL_PACKAGE: {
              return {
                ...state,
                allPackage: action.payload.allPackage,
                allPackageById: action.payload.allPackageById
              }
            }
            case COMMON_TYPES.FETCH_CURRENT_ITEM: {
              return {
                ...state,
                fetchCurrentItem: !state.fetchCurrentItem
              }
            }
            case COMMON_TYPES.UPDATE_INFO_ACCOUNT: {
              return {
                ...state,
                infoAccount: action.payload
              }
            }
            case COMMON_TYPES.SHOW_HIDE_LOADMORE: {
              return {
                ...state,
                hideLoadmore: action.payload
              }
            }
            default:
              return state
          }
    }

}


